const M=[0,null,1,null,2,3,null,4,null,5,null,6],O=27.5,z=4186;let s=[];const m=3;function E(o,i){const c=o.length>>1,n=new Float32Array(c);for(let e=1;e<c;e++){let h=0;for(let r=0;r<c;r++){const x=o[r]-o[r+e];h+=x*x}n[e]=h}n[0]=1;let d=0;for(let e=1;e<c;e++)d+=n[e],n[e]=n[e]*e/d;let t=-1,f=1/0;for(let e=2;e<c-1;e++)n[e]<.15&&n[e]<=n[e+1]&&1-n[e]>.7&&n[e]<f&&(f=n[e],t=e);if(t===-1)return{hz:-1,confidence:0};const l=n[t-1],I=n[t],a=n[t+1],u=2*(2*I-l-a),N=u===0?t:t+(a-l)/u,g=i/N,T=1-f;return{hz:g,confidence:T}}function _(o){if(o<O||o>z)return{noteIdx:null,hz:o,confidence:0};const i=12*Math.log2(o/440)+69,c=Math.round(i),n=Math.abs(i-c)*100;if(n>50)return{noteIdx:null,hz:o,confidence:0};const d=(c%12+12)%12,t=M[d],f=t!==null?Math.max(0,1-n/50):0;return{noteIdx:t,hz:o,confidence:f}}self.onmessage=({data:{samples:o,sampleRate:i}})=>{const c=E(o,i);if(c.hz<0){s=[],self.postMessage({noteIdx:null,hz:0,confidence:0});return}const n=_(c.hz);if(n.noteIdx===null){s=[],self.postMessage({noteIdx:null,hz:n.hz,confidence:0});return}const d={noteIdx:n.noteIdx,hz:n.hz,confidence:n.confidence*c.confidence};if(s.push(d),s.length>=m){const t=s[0];if(s.every(l=>l.noteIdx===t.noteIdx&&Math.abs(l.hz-t.hz)<5)){const l=s.reduce((a,u)=>a+u.hz,0)/s.length,I=s.reduce((a,u)=>a+u.confidence,0)/s.length;self.postMessage({noteIdx:t.noteIdx,hz:l,confidence:I}),s=[]}else s=[]}};
